SELECT * FROM nx_machine_device_manager


        AND nx_dm_device_id = #{deviceId}


        AND nx_dm_manager_id = #{managerId}


        AND nx_dm_enable = #{enable}


ORDER BY nx_dm_is_primary DESC, nx_dm_create_time DESC

SELECT dm.*, mm.nx_mm_id AS managerIdFull, mm.nx_mm_name AS managerName, mm.nx_mm_phone AS managerPhone, mm.nx_mm_wx_nickname AS managerWxNickname, mm.nx_mm_status AS managerStatus, CASE dm.nx_dm_is_primary WHEN 1 THEN '主要责任人（所有级别）' ELSE CONCAT(dm.nx_dm_notify_level, '级及以上') END AS roleDesc, at.nx_at_threshold AS threshold, at.nx_at_message AS thresholdMessage FROM nx_machine_device_manager dm LEFT JOIN nx_machine_market_manager mm ON dm.nx_dm_manager_id = mm.nx_mm_id LEFT JOIN nx_machine_alert_threshold at ON dm.nx_dm_device_id = at.nx_at_device_id AND dm.nx_dm_notify_level = at.nx_at_level
AND dm.nx_dm_device_id = #{deviceId}
AND dm.nx_dm_manager_id = #{managerId}
AND dm.nx_dm_enable = #{enable}
ORDER BY dm.nx_dm_is_primary DESC, dm.nx_dm_create_time DESC

SELECT COUNT(*) FROM nx_machine_device_manager


        AND nx_dm_device_id = #{deviceId}


        AND nx_dm_manager_id = #{managerId}

SELECT * FROM nx_machine_device_manager
WHERE nx_dm_device_id = #{deviceId}
  AND nx_dm_manager_id = #{managerId}

